VALUES
  ('islands-7fec267e-moex-00056', 'islands-7fec267e', 'islands-7fec267e-moex-114-3082b5f1', 'sub-islands-7fec267e-04', NULL, 'single_choice', '關於政府資訊限制公開或不予公開事由之敘述，下列何者錯誤？', '["政府機關為實施取締業務，而取得取締對象之相關資料，其公開將對實施目的造成困難者，應 限制或不予公開，並無例外", "公營事業機構經營之有關資料，其公開將妨害其經營上之正當利益者，應限制或不予公開，並 無例外", "政府機關作成意思決定前，內部單位之擬稿或其他準備作業，如對公益有必要者，仍得公開", "資訊之公開有侵害個人隱私，如對公益有必要者，仍得公開"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "301", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "一般行政"}'::jsonb, NULL),
  ('islands-7fec267e-moex-00057', 'islands-7fec267e', 'islands-7fec267e-moex-114-3082b5f1', 'sub-islands-7fec267e-04', NULL, 'single_choice', '經濟部智慧財產局訂頒商標識別性審查基準，如甲文創公司認經營環境受到限制，不服該審查基 準，關於其救濟，下列敘述何者正確？', '["甲得逕向憲法法庭聲請宣告該審查基準為違憲", "甲得逕向高等行政法院起訴請求撤銷該審查基準", "甲得請求行政法院聲請憲法法庭宣告該審查基準違憲", "需由經濟部智慧財產局依該審查基準對甲作成處分後，甲始得對該處分提起訴願、行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "301", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "一般行政"}'::jsonb, NULL),
  ('islands-7fec267e-moex-00058', 'islands-7fec267e', 'islands-7fec267e-moex-114-3082b5f1', 'sub-islands-7fec267e-04', NULL, 'single_choice', '關於訴願期間行政處分停止執行之敘述，下列何者錯誤？', '["訴願人於訴願程序終結前，亦得向行政法院聲請停止執行", "原行政處分之執行，原則上不因提起訴願而停止", "訴願人僅得就原行政處分之全部聲請停止執行，以維護行政權之完整性", "受理訴願機關認為原行政處分之合法性顯有疑義，得依職權命原處分機關停止執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "301", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "一般行政"}'::jsonb, NULL),
  ('islands-7fec267e-moex-00059', 'islands-7fec267e', 'islands-7fec267e-moex-114-3082b5f1', 'sub-islands-7fec267e-04', NULL, 'single_choice', '甲為公益團體，認為A工廠長年違法傾倒廢棄物，致使周遭農地受到污染，遂依廢棄物清理法規 定，以書面向當地主管機關乙請求依法行使公權力。若乙未在法定期間內採取任何作為，而甲欲 依行政訴訟法規定提起公益訴訟時，下列敘述何者正確？', '["本案仍應視其具體主張而提起特定訴訟類型", "甲必須證明自身權益亦遭受損害，始得提起本案訴訟", "向行政法院提起訴訟前，一律須經訴願程序", "此種訴訟屬於備位性質，必須限於無法提起其他行政訴訟時，始得提起"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "301", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "一般行政"}'::jsonb, NULL),
